void AssessorBruteWrite::pad_name (char* buf, u32 buf_sz, cstr name) {
    u32 len = (u32)std::strlen(name);
    if (len >= buf_sz) {
        len = buf_sz - 1;
    }
    std::memcpy(buf, name, len);
    buf[len] = '\0';
    for (u32 i = len; i < 28 && i < buf_sz - 1; ++i) {
        buf[i] = ' ';
    }
    if (28 < buf_sz) {
        buf[28] = '\0';
    }
}

void AssessorBruteWrite::emit_req_tok (FILE* out, cstr kind, cstr nm, u8 arg) {
    if (arg != 0) {
        std::fprintf(out, " : %s(%s, %u)", kind, nm, (u32)arg);
    } else {
        std::fprintf(out, " : %s(%s)", kind, nm);
    }
}

